let currentLang = "en";

function setLanguage(lang) {
  currentLang = lang;
  document.documentElement.lang = lang;
  document.querySelectorAll("[data-i18n]").forEach((node) => {
    const key = node.dataset.i18n;
    if (content[lang][key]) {
      node.textContent = content[lang][key];
    }
  });
  document.querySelectorAll("[data-lang]").forEach((button) => {
    button.classList.toggle("active", button.dataset.lang === lang);
  });
  renderProjects();
  renderResearch();
}

function renderProjects() {
  const all = projects[currentLang];
  renderProjectCollection("#erpGrid", all.filter((project) => project.name === "AEON ERP"));
  renderProjectCollection("#webDesignGrid", webDesignProjects[currentLang]);
  renderProjectCollection("#appsGrid", all.filter((project) => ["Vent", "Forge", "Bob", "undrgrnd"].includes(project.name)));
  renderProjectCollection("#socialGrid", socialMediaProjects[currentLang]);
  renderProjectCollection("#gameGrid", all.filter((project) => project.name === "Game Project"));
  const futureItems = [{
    name: currentLang === "en" ? "25+ Original Projects" : "25+ Özgün Proje",
    type: currentLang === "en" ? "Wider vision" : "Geniş vizyon",
    text: currentLang === "en" ? "A growing body of ideas across learning, culture, science, living systems, media, commerce, and human connection. Each begins as a question and becomes a world, product, or system worth building." : "Öğrenme, kültür, bilim, yaşam sistemleri, medya, ticaret ve insan bağlantısı üzerine büyüyen bir fikir alanı. Her biri bir soruyla başlar ve inşa edilmeye değer bir dünya, ürün veya sisteme dönüşür.",
    image: null,
    tags: [currentLang === "en" ? "Vision" : "Vizyon"]
  }];
  renderProjectCollection("#upcomingGrid", futureItems, "future-card");
}

function renderProjectCollection(selector, items, extraClass = "") {
  const grid = document.querySelector(selector);
  if (!grid) return;
  grid.innerHTML = items.map((project) => {
    const cover = projectCovers[project.name] || project.image;
    return `
      <button class="project-card ${extraClass}" type="button" data-project-key="${encodeURIComponent(project.name)}">
        <div class="project-media">
          ${cover ? `<img class="project-cover" src="${cover}" alt="${project.name} logo" onerror="this.remove()">` : `<span class="project-wordmark">${project.wordmark || String(project.name).slice(0, 1)}</span>`}
        </div>
        <div class="project-body">
          <h3>${project.name}</h3>
          <p>${project.text}</p>
        </div>
      </button>
    `;
  }).join("");
}

function getPortfolioItems() {
  const futureItems = [{
    name: currentLang === "en" ? "25+ Original Projects" : "25+ Özgün Proje",
    type: currentLang === "en" ? "Wider vision" : "Geniş vizyon",
    text: currentLang === "en" ? "A growing body of ideas across learning, culture, science, living systems, media, commerce, and human connection. Each begins as a question and becomes a world, product, or system worth building." : "Öğrenme, kültür, bilim, yaşam sistemleri, medya, ticaret ve insan bağlantısı üzerine büyüyen bir fikir alanı. Her biri bir soruyla başlar ve inşa edilmeye değer bir dünya, ürün veya sisteme dönüşür.",
    image: null,
    tags: [currentLang === "en" ? "Vision" : "Vizyon"]
  }];
  return [...projects[currentLang], ...webDesignProjects[currentLang], ...socialMediaProjects[currentLang], ...futureItems];
}

function openProjectByKey(key) {
  const project = getPortfolioItems().find((item) => item.name === key);
  if (!project) return;
  const gallery = project.gallery || projectGalleries[project.name] || (project.image ? [project.image] : []);
  const modal = document.querySelector("#articleModal");
  const modalContent = document.querySelector("#articleModalContent");
  const galleryMarkup = gallery.length
    ? `<div class="project-gallery"><div class="project-gallery-grid">${gallery.map((image) => `<img src="${image}" alt="${project.name} screenshot" onerror="this.remove()">`).join("")}</div></div>`
    : `<div class="project-no-preview">${content[currentLang].projectNoPreview}</div>`;
  modalContent.innerHTML = `
    <div class="article-modal-heading">
      <span class="research-category">${project.type}</span>
      <h2 id="articleModalTitle">${project.name}</h2>
      ${project.status ? `<div class="project-modal-status"><span>${content[currentLang].projectStatusLabel}</span><strong>${project.status}</strong></div>` : ""}
      <p class="research-lead">${project.text}</p>
    </div>
      ${project.detail || project.business ? `<div class="project-detail-grid">
      ${project.detail ? `<div><span>${content[currentLang].projectDetailLabel}</span><p>${project.detail}</p></div>` : ""}
      ${project.business ? `<div><span>${content[currentLang].projectBusinessLabel}</span><p>${project.business}</p></div>` : ""}
    </div>` : ""}
    ${galleryMarkup}
  `;
  modal.hidden = false;
  document.body.classList.add("modal-open");
  document.querySelector(".article-modal-close").focus();
}

function renderResearch() {
  const article = document.querySelector("#researchArticle");
  const articles = [researchArticles[currentLang], secondResearchArticle[currentLang], thirdResearchArticle[currentLang], fourthResearchArticle[currentLang], fifthResearchArticle[currentLang], sixthResearchArticle[currentLang]];
  article.innerHTML = `
    <div class="research-highlight">
      <div class="research-highlight-heading">
        <span class="research-category">${content[currentLang].researchKicker}</span>
        <h3>${content[currentLang].researchTitle}</h3>
        <p>${content[currentLang].researchIntro}</p>
      </div>
      <div class="research-title-list">
        ${articles.map((data, index) => `<button class="research-title-item" type="button" data-research-index="${index}"><span>${data.title}</span><span aria-hidden="true">↗</span></button>`).join("")}
      </div>
    </div>
  `;
}

function openResearchArticle(index) {
  const articles = [researchArticles[currentLang], secondResearchArticle[currentLang], thirdResearchArticle[currentLang], fourthResearchArticle[currentLang], fifthResearchArticle[currentLang], sixthResearchArticle[currentLang]];
  const data = articles[index];
  const modal = document.querySelector("#articleModal");
  const content = document.querySelector("#articleModalContent");
  content.innerHTML = `
    <div class="article-modal-heading">
      <span class="research-category">${data.category}</span>
      <span class="research-label">${data.label}</span>
      <h2 id="articleModalTitle">${data.title}</h2>
      <p class="research-meta">${data.meta}</p>
      <p class="research-lead">${data.lead}</p>
    </div>
    <div class="article-body">${data.paragraphs.map((paragraph) => `<p>${paragraph}</p>`).join("")}</div>
  `;
  modal.hidden = false;
  document.body.classList.add("modal-open");
  document.querySelector(".article-modal-close").focus();
}

function closeResearchArticle() {
  document.querySelector("#articleModal").hidden = true;
  document.body.classList.remove("modal-open");
}

document.querySelector("#researchArticle").addEventListener("click", (event) => {
  const card = event.target.closest("[data-research-index]");
  if (card) {
    openResearchArticle(Number(card.dataset.researchIndex));
  }
});

document.addEventListener("click", (event) => {
  const card = event.target.closest("[data-project-key]");
  if (card) {
    openProjectByKey(decodeURIComponent(card.dataset.projectKey));
  }
});

document.querySelectorAll("[data-close-article]").forEach((node) => {
  node.addEventListener("click", closeResearchArticle);
});

let lightboxImages = [];
let lightboxIndex = 0;

function renderLightboxImage() {
  const image = lightboxImages[lightboxIndex];
  if (!image) return;
  const lightboxImage = document.querySelector("#lightboxImage");
  lightboxImage.src = image.src;
  lightboxImage.alt = image.alt;
  document.querySelector("#lightboxCount").textContent = `${lightboxIndex + 1} / ${lightboxImages.length}`;
}

function closeImageLightbox() {
  document.querySelector("#imageLightbox").hidden = true;
}

document.addEventListener("click", (event) => {
  const image = event.target.closest(".project-gallery-grid img");
  if (image) {
    const lightbox = document.querySelector("#imageLightbox");
    lightboxImages = Array.from(document.querySelectorAll(".project-gallery-grid img"));
    lightboxIndex = Math.max(0, lightboxImages.indexOf(image));
    renderLightboxImage();
    lightbox.hidden = false;
  }
});

document.querySelector("#lightboxPrevious").addEventListener("click", () => {
  lightboxIndex = (lightboxIndex - 1 + lightboxImages.length) % lightboxImages.length;
  renderLightboxImage();
});

document.querySelector("#lightboxNext").addEventListener("click", () => {
  lightboxIndex = (lightboxIndex + 1) % lightboxImages.length;
  renderLightboxImage();
});

document.querySelectorAll("[data-close-image]").forEach((node) => {
  node.addEventListener("click", closeImageLightbox);
});

document.addEventListener("keydown", (event) => {
  if (event.key === "Escape" && !document.querySelector("#imageLightbox").hidden) {
    closeImageLightbox();
  } else if (event.key === "Escape" && !document.querySelector("#articleModal").hidden) {
    closeResearchArticle();
  }
});

document.querySelectorAll("[data-lang]").forEach((button) => {
  button.addEventListener("click", () => setLanguage(button.dataset.lang));
});

setLanguage(currentLang);
